INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '49854a14-84e7-48a7-88b9-1b23969d40ae',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Routing — Parameters, Prefixes, and Plugin-Based Grouping$escape$,
  $escape$Fastify routes are registered via `fastify.get()`, `fastify.post()`, or the generic `fastify.route()` with a full config object. Route parameters use `:param` syntax and land in `request.params` — wildcard segments use `*` for catch-all matching.

Grouping routes under a shared prefix is done through `fastify.register()` with the `prefix` option. Each registered plugin gets its own encapsulated scope, so hooks, decorators, and error handlers defined inside don't leak out. This is Fastify's core encapsulation model — not just a naming convenience.

For typed parameters, pair your route with a JSON Schema on `schema.params`. Fastify validates and coerces inputs before your handler runs, so `request.params.id` is already the right type — no manual parsing needed.

Use `fastify.register()` to split route groups into separate files, passing the `fastify` instance into each plugin. This keeps route modules fully self-contained and composable without a global router object.$escape$,
  $escape$import Fastify from 'fastify';

const app = Fastify();

async function userRoutes(fastify, opts) {
  fastify.get('/:id', {
    schema: {
      params: { type: 'object', properties: { id: { type: 'integer' } }, required: ['id'] }
    },
    handler: async (request, reply) => {
      return { userId: request.params.id };
    }
  });

  fastify.post('/', async (request, reply) => {
    reply.code(201).send({ created: true });
  });
}

app.register(userRoutes, { prefix: '/users' });
await app.listen({ port: 3000 });$escape$,
  $escape$typescript$escape$,
