INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '94c2f99b-e5ff-4eb8-b077-d5b5a934e59f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify's Plugin System IS Your DI Container$escape$,
  $escape$Fastify doesn't ship a traditional DI container — it ships something better: a plugin-scoped encapsulation model via `fastify-plugin` and `decorate`. Every dependency lives on the `fastify` instance, injected via `fastify.decorate()` and scoped by the plugin tree. Child plugins inherit parent decorations; siblings are isolated unless you use `fastify-plugin` to break encapsulation upward.

This matters for testability. Instead of mocking a global service registry, you build a test instance and register only the plugins your handler needs. Swap a real `pg` pool for a `pgmock` by registering a different plugin before your route plugin — the handler never changes.

Manual wiring (passing deps through closures or module singletons) breaks this model. You lose scoping, you can't swap implementations per test, and you fight Fastify's lifecycle instead of using it. The `fastify.decorate` + `fastify-plugin` pattern is the idiomatic DI — use it as the framework intends, and testability is nearly free.$escape$,
  $escape$import Fastify from 'fastify';
import fp from 'fastify-plugin';

// Real DB plugin
const dbPlugin = fp(async (fastify) => {
  fastify.decorate('db', realPgPool);
});

// Fake DB plugin for tests
const fakeDbPlugin = fp(async (fastify) => {
  fastify.decorate('db', { query: async () => ({ rows: [{ id: 1 }] }) });
});

// Route plugin — depends on fastify.db, doesn't care which
const userRoutes = fp(async (fastify) => {
  fastify.get('/users', async () => {
    const { rows } = await fastify.db.query('SELECT * FROM users');
    return rows;
  });
});

// In tests: register fakeDbPlugin instead of dbPlugin
const app = Fastify();
await app.register(fakeDbPlugin);
await app.register(userRoutes);
await app.ready();$escape$,
  $escape$javascript$escape$,
