INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '19aa5b90-804a-475c-a283-ad8166f901c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Project Structure — Vertical Slices Beat MVC at Scale$escape$,
  $escape$Fastify's plugin system is purpose-built for vertical slice architecture. Each feature registers itself as an encapsulated plugin via `fastify.register()`, scoping its routes, decorators, hooks, and schemas internally — MVC layers fight this by spreading a single feature across `controllers/`, `services/`, and `models/` directories, making encapsulation impossible.

A vertical slice in Fastify means one folder per feature: `src/features/users/` contains `routes.ts`, `schema.ts`, `service.ts`, and `repository.ts`. The routes file calls `fastify.register()` on the feature plugin, which in turn registers child plugins for sub-resources. This maps directly onto Fastify's directed acyclic plugin graph — decorators added inside a plugin don't leak to siblings, so `users/` can decorate `fastify.userRepo` without polluting `orders/`.

Use `@fastify/autoload` to mount feature folders automatically. Point it at `src/features/` and it traverses subdirectories, calling `register()` on every `index.ts` it finds. Layering convention: routes validate with JSON Schema (Fastify compiles these via fast-json-stringify), delegate to a service, which owns business logic, and call a repository that wraps raw `pg` or Prisma queries. No framework coupling below the route layer.$escape$,
  $escape$// src/features/users/index.ts
import { FastifyPluginAsync } from 'fastify'
import { getUserSchema, createUserSchema } from './schema'
import { UserService } from './service'

const usersPlugin: FastifyPluginAsync = async (fastify) => {
  const service = new UserService(fastify.pg) // pg decorated at app root

  fastify.get<{ Params: { id: string } }>(
    '/:id',
    { schema: getUserSchema },
    async (req) => service.findById(req.params.id)
  )

  fastify.post(
    '/',
    { schema: createUserSchema },
    async (req) => service.create(req.body)
  )
}

export default usersPlugin$escape$,
  $escape$typescript$escape$,
