INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e70ae619-6fcf-456c-9703-c8c5a4d62ee6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Middleware — Hook Lifecycle, Scope, and Why Order Is Everything$escape$,
  $escape$Fastify has no Express-style `app.use()`. Middleware is hooks — and hooks have a strict lifecycle: `onRequest → preParsing → preValidation → preHandler → handler → onSend → onResponse`. Register hooks globally with `fastify.addHook()` or scope them per-route via the route options object. Scoping is done through encapsulation: wrap routes in `fastify.register()` and any hooks added inside that scope are invisible outside it. Order within a scope is registration order — a `preHandler` auth check registered after a logging hook runs second, not first. This trips up teams who assume plugin order doesn't matter. A common pattern: register global `onRequest` rate-limiting, then per-plugin `preHandler` auth, then per-route `preValidation` for input schema coercion. One subtle gotcha — `fastify.addHook('onRequest', ...)` called inside a plugin without `fastify-plugin` wrapping is automatically scoped. Wrap with `fp()` to promote it to global scope. Miss this and your auth hook silently skips unregistered routes.$escape$,
  $escape$import fp from 'fastify-plugin';
import Fastify from 'fastify';

const fastify = Fastify();

// Global: runs on every route
fastify.addHook('onRequest', async (req, reply) => {
  req.log.info({ url: req.url }, 'incoming request');
});

// Scoped: only routes inside this register block
fastify.register(async (instance) => {
  instance.addHook('preHandler', async (req, reply) => {
    if (!req.headers.authorization) {
      return reply.code(401).send({ error: 'Unauthorized' });
    }
  });

  instance.get('/secure', async () => ({ data: 'protected' }));
});

// This route skips the preHandler above — different scope
fastify.get('/public', async () => ({ data: 'open' }));

await fastify.listen({ port: 3000 });$escape$,
