INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f5050e09-7525-428c-8548-ce65808d9ca6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Global Error Handling — Consistent Error Responses at Scale$escape$,
  $escape$Fastify's `setErrorHandler` is your single choke point for all unhandled errors — register it once on the root instance and every thrown error, including those from plugins and child scopes, flows through it. Unlike Express middleware, Fastify passes a fully typed `FastifyError` with a `statusCode` property, so you can distinguish a 404 from a 500 without parsing message strings.

For validation errors, Fastify auto-generates a 400 with a `message` field from Ajv. Override the shape inside `setErrorHandler` by checking `error.validation` — it's a non-null array when the error originated from schema validation.

Always return a consistent envelope: `{ success, code, message, details? }`. This prevents clients from branching on wildly different error shapes. Pair this with `reply.log.error(error)` inside the handler so OpenTelemetry traces capture the stack without leaking it to the response. Avoid throwing raw `Error` objects — use `fastify.httpErrors` (from `@fastify/sensible`) to get pre-typed HTTP errors with correct status codes baked in.$escape$,
  $escape$import Fastify from 'fastify';
import sensible from '@fastify/sensible';

const app = Fastify({ logger: true });
await app.register(sensible);

app.setErrorHandler((error, request, reply) => {
  reply.log.error(error);

  const statusCode = error.statusCode ?? 500;
  const isValidation = Array.isArray(error.validation);

  reply.status(statusCode).send({
    success: false,
    code: isValidation ? 'VALIDATION_ERROR' : (error.code ?? 'INTERNAL_ERROR'),
    message: statusCode < 500 ? error.message : 'An unexpected error occurred',
    details: isValidation ? error.validation : undefined,
  });
});

app.get('/user/:id', async (request) => {
  const { id } = request.params as { id: string };
  if (!id.match(/^\d+$/)) throw app.httpErrors.badRequest('id must be numeric');
  return { id };
});$escape$,
  $escape$typescript$escape$,
