INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed5710e0-3f41-4275-abab-389ad5386ee4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Structured Logging — Correlation IDs and Request Tracing Built In$escape$,
  $escape$Fastify ships with pino as its default logger, giving you structured JSON logs out of the box — no setup required. Every request gets its own child logger accessible via `request.log`, which automatically includes `reqId` for correlation. You can customize the ID strategy with `genReqId` on the server instance.

For distributed tracing, propagate incoming `x-request-id` headers into Fastify's `reqId` so logs chain across services. Register a `onRequest` hook to extract and forward the header, then decorate the request with it for use in handlers.

Pino's child loggers are zero-copy — `request.log.info({ userId })` merges context without cloning the base logger. Use `serializers` at the server level to redact sensitive fields like `authorization` headers globally.

Set `logger: { level: 'info', redact: ['req.headers.authorization'] }` in server options. In production, pipe pino output through `pino-pretty` only in dev — in prod, ship raw JSON to your collector (Loki, Datadog, etc.) for structured querying.$escape$,
  $escape$import Fastify from 'fastify'

const app = Fastify({
  logger: {
    level: 'info',
    redact: ['req.headers.authorization'],
  },
  genReqId: (req) => req.headers['x-request-id'] ?? crypto.randomUUID(),
})

app.addHook('onRequest', async (request) => {
  request.log.info({ url: request.url }, 'incoming request')
})

app.get('/user/:id', async (request) => {
  request.log.info({ userId: request.params.id }, 'fetching user')
  return { id: request.params.id }
})$escape$,
  $escape$typescript$escape$,
