INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4a7073e0-c24f-4162-8b13-ecb52217da9b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify Background Jobs — Queues, Schedules, and Worker Patterns$escape$,
  $escape$Fastify has no built-in job queue, but its plugin system makes integration clean. The go-to pairing is `fastify-bullmq` (a thin wrapper over BullMQ + Redis). Register it as a plugin so the queue shares the Fastify lifecycle — `onClose` hooks drain queues gracefully on shutdown, preventing job loss during deploys.

For scheduled jobs, avoid `setInterval` in your server process. Instead, define a dedicated worker entrypoint that imports your queue definitions but never calls `fastify.listen()`. This separates HTTP concerns from CPU-bound processing and lets you scale workers independently.

Use `fastify.decorate('queue', queue)` to expose the BullMQ queue instance across routes, keeping enqueue calls inside route handlers rather than bleeding queue logic into business services. For job definitions, colocate the processor function with its route feature folder — not in a global `workers/` directory — to stay aligned with Fastify's vertical-slice plugin model.

Enable `removeOnComplete: { count: 100 }` and `removeOnFail: { age: 86400 }` on every job to prevent Redis memory bloat in production.$escape$,
  $escape$import Fastify from 'fastify';
import { Queue, Worker } from 'bullmq';
import Redis from 'ioredis';

const connection = new Redis({ maxRetriesPerRequest: null });

export async function emailPlugin(fastify) {
  const emailQueue = new Queue('email', { connection });

  fastify.decorate('emailQueue', emailQueue);

  fastify.addHook('onClose', async () => {
    await emailQueue.close();
  });

  fastify.post('/send-welcome', async (req, reply) => {
    await fastify.emailQueue.add('welcome', { userId: req.body.userId }, {
      attempts: 3,
      backoff: { type: 'exponential', delay: 1000 },
      removeOnComplete: { count: 100 },
      removeOnFail: { age: 86400 },
    });
    return reply.code(202).send({ queued: true });
  });
}

// worker.ts — separate entrypoint, no fastify.listen()
new Worker('email', async (job) => {
  await sendEmail(job.data.userId);
}, { connection });$escape$,
