INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a34f34a1-db2b-4916-a5d9-4cfa705174e1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Fastify's Plugin System — The Batteries-Included Architecture You Build Yourself$escape$,
  $escape$Fastify doesn't ship with an ORM, auth layer, or mailer baked in — but its encapsulated plugin system lets you compose exactly those batteries with surgical precision. Every `fastify.register()` call creates an isolated scope: decorators, hooks, and route prefixes defined inside don't leak out unless you explicitly use `fastify-plugin` to break encapsulation. This is Fastify's answer to Django's app registry — modular, but opt-in global state.

Practical pattern: register your database connector (e.g. `@fastify/postgres`) at root scope via `fastify-plugin`, then register your domain routes as child plugins. Child plugins inherit `fastify.pg` but remain isolated from each other's hooks. Combine this with `fastify.decorate()` for request-scoped context and `addHook('onRequest', ...)` per plugin for auth guards — you get Django-style cohesion without the magic. Auto-documentation comes free via `@fastify/swagger`, which reads your `schema` objects on each route definition and emits OpenAPI — no decorators, no reflection, just the JSON Schema you already wrote for validation.$escape$,
  $escape$import Fastify from 'fastify'
import fp from 'fastify-plugin'
import postgres from '@fastify/postgres'
import swagger from '@fastify/swagger'

const app = Fastify()

// Root-scope: available to all child plugins
await app.register(fp(postgres), { connectionString: process.env.DATABASE_URL })
await app.register(swagger, { openapi: { info: { title: 'API', version: '1.0.0' } } })

// Encapsulated plugin — auth hook stays local
await app.register(async (instance) => {
  instance.addHook('onRequest', async (req) => {
    if (!req.headers.authorization) throw instance.httpErrors.unauthorized()
  })
  instance.get('/users', {
    schema: { response: { 200: { type: 'array', items: { type: 'object', properties: { id: { type: 'integer' }, name: { type: 'string' } } } } } },
    handler: async () => (await instance.pg.query('SELECT id, name FROM users')).rows
  })
}, { prefix: '/api' })

await app.listen({ port: 3000 })$escape$,
  $escape$javascript$escape$,
